import React, { useEffect, useState } from "react";
import Button from "./ui/Button";
import { useNavigate, useParams } from "react-router-dom";

const BookShow = () => {
  const { id } = useParams();
  const [books, setBooks] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    fetch(`http://localhost:3000/api/book/${id}`)
      .then((response) => response.json())
      .then((data) => setBooks(data))
      .catch((error) => console.error("erreur de fetching data ", error));
  }, [id]);

  const handleDelete = () => {
 
    fetch(`http://localhost:3000/api/book/${id}`, {
      method: "DELETE",
      headers: {
        "Content-Type": "application/json",
      },
    })
      .then((response) => {
        if (!response.ok) {
          throw new Error("Erreur lors de la suppression du livre");
        }
        alert("Livre supprimé avec succès !");
        // Recharger la liste ou rediriger si nécessaire
        navigate("/bookList");
      })
      .catch((error) => console.error("erreur de suppression ", error));

  };

  return (
    <div className="w-full h-screen flex justify-center items-center ">
      <div className="flex flex-col justify-center items-center w-max p-10 gap-5 border-2 bo">
        <div className="">
          <ul>
            <li>
              <span className="text-blue-300">id:</span>
              {books._id}
            </li>
            <li>
              <span className="text-blue-300">title:</span>
              {books.title}
            </li>
            <li>
              <span className="text-blue-300">description:</span>
              {books.description}
            </li>
            <li>
              <span className="text-blue-300">nombre des page:</span>
              {books.page}
            </li>
          </ul>
        </div>
        <div className="flex">
          <Button
            className="bg-green-400 mx-5"
            onClick={() => navigate(`/bookUpdate/${id}`)}
          >
            modifier
          </Button>
          <Button className="bg-red-300 mx-5" onClick={handleDelete}>
            supprimer
          </Button>
        </div>
      </div>
    </div>
  );
};

export default BookShow;
